    ...awsOptions
  } = parseUpdateItemOptions(entity, options)

  const ExpressionAttributeNames = {
    ...optionsExpressionAttributeNames,
    ...updateExpressionAttributeNames
  }

  const ExpressionAttributeValues = {
    ...optionsExpressionAttributeValues,
    ...updateExpressionAttributeValues
  }

  const requiredIfConditions: string[] = []
  const requiredIfNames: Record<string, string> = {}
  let requiredIfIndex = 0
  for (const [dependentName, dependent] of Object.entries(entity.schema.attributes)) {
    if (dependent.props.required === 'always' || dependentName in parsedItem) continue
    for (const { attributeName, values } of dependent.props.requiredIf ?? []) {
